 const driverSchema=z.object({companyId:z.string().uuid(),code:z.string().trim().min(1).max(60),fullName:z.string().trim().min(2).max(180),phone:z.string().trim().max(80).optional().default(''),licenseNo:z.string().trim().max(100).optional().default(''),licenseCategory:z.string().trim().max(40).optional().default(''),licenseExpiry:z.string().date().nullable().optional(),employmentType:z.enum(['EMPLOYEE','CONTRACTOR','THIRD_PARTY']).default('EMPLOYEE'),active:z.boolean().default(true),notes:z.string().trim().max(2000).optional().default('')});
