 const tripSchema=z.object({companyId:z.string().uuid(),tripDate:z.string().date(),vehicleId:z.string().uuid(),driverId:z.string().uuid().nullable().optional(),routeId:z.string().uuid().nullable().optional(),shipmentId:z.string().uuid().nullable().optional(),purpose:z.string().trim().min(2).max(180),plannedDepartureAt:z.string().datetime({offset:true}).nullable().optional(),odometerStart:z.coerce.number().min(0),tollsCost:z.coerce.number().min(0).default(0),parkingCost:z.coerce.number().min(0).default(0),otherCost:z.coerce.number().min(0).default(0),notes:z.string().trim().max(2000).optional().default('')});
