 const maintenanceSchema=z.object({companyId:z.string().uuid(),vehicleId:z.string().uuid(),maintenanceType:z.enum(['SERVICE','REPAIR','OIL_CHANGE','TIRES','INSPECTION','REGISTRATION','INSURANCE','OTHER']),reportedDate:z.string().date(),odometerKm:z.coerce.number().min(0).nullable().optional(),supplierId:z.string().uuid().nullable().optional(),description:z.string().trim().min(2).max(3000),partsDescription:z.string().trim().max(3000).optional().default(''),costAmount:z.coerce.number().min(0).default(0),downtimeHours:z.coerce.number().min(0).default(0),nextServiceDate:z.string().date().nullable().optional(),nextServiceOdometer:z.coerce.number().min(0).nullable().optional(),accountId:z.string().uuid().nullable().optional(),currency:z.string().trim().min(3).max(8).default('ALL'),notes:z.string().trim().max(2000).optional().default('')});
